const e={configTemplates:{intro:{t:0,b:{t:2,i:[{t:3}],s:"Sofort einfügbare Klipper-Konfigurationsblöcke und Makros — Startsequenzen, Filamenthandhabung, Input Shaping, Bed Mesh und mehr. Kopiere einen und füge ihn in deine printer.cfg ein (der Config Editor ist ein guter Ort dafür)."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"Hilfe"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"Über Config Templates"}},close:{t:0,b:{t:2,i:[{t:3}],s:"Schließen"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"Verwendung"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"Filtere nach Kategorie, um ein Makro oder einen Konfigurationsblock zu finden."}},{t:0,b:{t:2,i:[{t:3}],s:"Lies die Beschreibung und welche Sektionen benötigt werden."}},{t:0,b:{t:2,i:[{t:3}],s:"Kopiere die Vorlage, füge sie in deine Konfiguration ein und passe die Werte an."}}],topics:{what:{title:{t:0,b:{t:2,i:[{t:3}],s:"Was das ist"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Eine kuratierte Sammlung gängiger Klipper-Bausteine: gcode_macros (PRINT_START, PAUSE/RESUME, Filament laden/entladen, M600) und Konfigurationssektionen ([input_shaper], [bed_mesh], [firmware_retraction], …). Sie sind Ausgangspunkte — lies jeden durch und stimme ihn auf deine Maschine ab."}}},insert:{title:{t:0,b:{t:2,i:[{t:3}],s:"Eine Vorlage einfügen"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Kopiere eine Vorlage und füge sie in deine printer.cfg ein — die Raw-Ansicht des Config Editors ist ein praktischer Ort dafür. Nach dem Speichern wird sie durch einen Firmware-Neustart wirksam. Überprüfe immer zuerst die Werte; die Standardwerte hier sind sinnvoll, aber nicht auf deinen Drucker abgestimmt."}}},sections:{title:{t:0,b:{t:2,i:[{t:3}],s:"Benötigte Sektionen"}},body:{t:0,b:{t:2,i:[{t:3}],s:"Jede Vorlage listet die Konfigurationssektionen auf, die sie definiert oder von denen sie abhängt. Wenn eine Sektion bereits in deiner Konfiguration existiert, füge die Schlüssel zusammen, anstatt ein Duplikat einzufügen (eine doppelte Sektion wird beim Start abgelehnt)."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"Glossar"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{template:{term:{t:0,b:{t:2,i:[{t:3}],s:"Vorlage"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Ein sofort einfügbares Snippet aus Klipper-Konfiguration oder Makro-G-code, das du in deine printer.cfg kopierst."}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"gcode_macro"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Ein benannter Befehl, den du in der Konfiguration definierst (z. B. PRINT_START) und der eine Sequenz von G-code ausführt."}}},section:{term:{t:0,b:{t:2,i:[{t:3}],s:"Sektion"}},def:{t:0,b:{t:2,i:[{t:3}],s:"Ein [in eckigen Klammern] stehender Konfigurationsblock, z. B. [bed_mesh] — die Einheit, in der die Klipper-Konfiguration gruppiert wird."}}}}},category:{label:{t:0,b:{t:2,i:[{t:3}],s:"Kategorie"}},all:{t:0,b:{t:2,i:[{t:3}],s:"Alle Kategorien"}}},template:{copy:{t:0,b:{t:2,i:[{t:3}],s:"Kopieren"}},copied:{t:0,b:{t:2,i:[{t:3}],s:"Kopiert!"}},requires:{t:0,b:{t:2,i:[{t:3,v:"Sektionen: "},{t:4,k:"sections"}]}},requiresNone:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},count:{t:0,b:{t:2,i:[{t:4,k:"n"},{t:3,v:" Vorlagen"}]}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"Vorlagen werden geladen…"}},error:{t:0,b:{t:2,i:[{t:3}],s:"Die Vorlagen konnten nicht geladen werden."}},empty:{t:0,b:{t:2,i:[{t:3}],s:"Keine Vorlagen in dieser Kategorie."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"Erneut versuchen"}}},categories:{config_blocks:{t:0,b:{t:2,i:[{t:3}],s:"Konfig-Blöcke"}},macros:{t:0,b:{t:2,i:[{t:3}],s:"Makros"}}}}};export{e as default};
